(function(){
'use strict';
const configs={
dashboard:{endpoint:'/api/dashboard/overview',kpis:'#dashboardKpis',stamp:'#dashboardGeneratedAt',charts:['#ageStructureChart','#populationMovementChart','#genderStructureChart','#partyMemberChart'],keys:['households','businessSectors','vehicles','livestock']},
dashboardHouseholds:{endpoint:'/api/dashboard/households',kpis:'#dashboardHouseholdsKpis',stamp:'#dashboardHouseholdsGeneratedAt',charts:['#dashboardHouseholdsChartOne','#dashboardHouseholdsChartTwo','#dashboardHouseholdsChartThree','#dashboardHouseholdsExtra'],keys:['households','gps','profiles','top'],top:'#dashboardHouseholdsExtra'},
dashboardPopulation:{endpoint:'/api/dashboard/population',kpis:'#dashboardPopulationKpis',stamp:'#dashboardPopulationGeneratedAt',charts:['#dashboardPopulationChartOne','#dashboardPopulationChartTwo','#dashboardPopulationChartThree','#dashboardPopulationExtra'],keys:['gender','ages','labor','healthInsurance']},
dashboardBusiness:{endpoint:'/api/dashboard/business',kpis:'#dashboardBusinessKpis',stamp:'#dashboardBusinessGeneratedAt',charts:['#dashboardBusinessChartOne','#dashboardBusinessChartTwo','#dashboardBusinessChartThree'],keys:['types','sectors','scales'],top:'#dashboardBusinessExtra'},
dashboardVehicles:{endpoint:'/api/dashboard/vehicles',kpis:'#dashboardVehiclesKpis',stamp:'#dashboardVehiclesGeneratedAt',charts:['#dashboardVehiclesChartOne','#dashboardVehiclesChartTwo','#dashboardVehiclesChartThree'],keys:['types','households','areas'],top:'#dashboardVehiclesExtra'},
dashboardLivestock:{endpoint:'/api/dashboard/livestock',kpis:'#dashboardLivestockKpis',stamp:'#dashboardLivestockGeneratedAt',charts:['#dashboardLivestockChartOne','#dashboardLivestockChartTwo','#dashboardLivestockChartThree'],keys:['types','scale','areas'],top:'#dashboardLivestockExtra'},
dashboardGis:{endpoint:'/api/dashboard/gis',kpis:'#dashboardGisKpis',stamp:'#dashboardGisGeneratedAt',charts:['#dashboardGisChartOne','#dashboardGisChartTwo','#dashboardGisChartThree'],keys:['gps','business','layers'],top:'#dashboardGisExtra'},
dashboardReports:{endpoint:'/api/dashboard/reports',kpis:'#dashboardReportsKpis',stamp:'#dashboardReportsGeneratedAt',charts:['#dashboardReportsChartOne','#dashboardReportsChartTwo','#dashboardReportsChartThree'],keys:['reports','exports','empty'],top:'#dashboardReportsExtra'}
};
const cache=new Map(),ttl=30000;
const q=(s,r)=> (r||document).querySelector(s);
const qa=(s,r)=> Array.from((r||document).querySelectorAll(s));
function esc(v){return String(v==null?'':v).replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#039;'}[c]));}
function fmt(v){return new Intl.NumberFormat('vi-VN').format(Number(v||0));}
function empty(msg){return '<div class="dashboard-empty-chart text-muted">'+esc(msg||'Chưa có dữ liệu')+'</div>';}
function params(screen){const host=q('#'+screen+'Screen'),p=new URLSearchParams();if(!host)return p;qa('[data-dashboard-filter]',host).forEach(el=>{const v=String(el.value||'').trim();if(v)p.set(el.dataset.dashboardFilter,v);});return p;}
async function fetchData(url){if(typeof api==='function')return api(url,{cacheTtl:ttl});const token=localStorage.getItem('thon09_token')||window.App?.token||'';const res=await fetch(url,{headers:{Accept:'application/json',Authorization:token?'Bearer '+token:''},cache:'no-store'});const json=await res.json().catch(()=>null);if(!res.ok||!json?.ok)throw new Error(json?.error?.message||'Không tải được Dashboard');return json.data||{};}
function canRead(screen){return typeof window.thon09CanAccess!=='function'||window.thon09CanAccess(screen,'read');}
function renderDenied(screen){const cfg=configs[screen];if(!cfg)return;const host=q(cfg.kpis)||q('#'+screen+'Screen');if(host)host.innerHTML='<div class="empty-state text-muted py-4 text-center">Bạn không có quyền truy cập</div>';}
async function load(screen,force){const cfg=configs[screen];if(!cfg)return;if(!canRead(screen)){renderDenied(screen);return;}bind(screen);const query=params(screen).toString();const url=cfg.endpoint+(query?'?'+query:'');const hit=cache.get(url);if(!force&&hit&&hit.expires>Date.now()){render(screen,hit.data);return;}try{setBusy(screen,true);const data=await fetchData(url);cache.set(url,{data,expires:Date.now()+ttl});render(screen,data);}catch(e){renderError(cfg,e);}finally{setBusy(screen,false);}}
function setBusy(screen,on){qa('[data-dashboard-refresh]',q('#'+screen+'Screen')||document).forEach(btn=>btn.disabled=!!on);}
function render(screen,data){const cfg=configs[screen];if(!cfg)return;renderKpis(cfg.kpis,data.kpis||[]);stamp(cfg.stamp,data.generatedAt);const charts=data.charts||{};(cfg.charts||[]).forEach((sel,i)=>{const key=cfg.keys[i];if(key==='layers')list(sel,data.layers||[]);else if(key==='reports')list(sel,data.reports||[]);else if(key==='exports')list(sel,data.exports||[]);else if(key==='empty')list(sel,[]);else chart(sel,charts[key]||[]);});if(cfg.top)extra(cfg.top,data);}
function renderKpis(sel,kpis){const host=q(sel);if(!host)return;host.innerHTML=(kpis||[]).map(c=>'<article class="dashboard-kpi dashboard-tone-'+esc(c.tone||'green')+'"><div class="dashboard-kpi-head"><span class="dashboard-kpi-icon"><i class="fa-solid '+esc(c.icon||'fa-chart-simple')+'"></i></span><span class="dashboard-kpi-label">'+esc(c.label)+'</span></div><div class="dashboard-kpi-value"><strong>'+fmt(c.value)+'</strong><span>'+esc(c.unit||'')+'</span></div></article>').join('')||empty();}
function stamp(sel,value){const el=q(sel);if(!el)return;const d=value?new Date(value):new Date();el.textContent='Cập nhật lúc '+new Intl.DateTimeFormat('vi-VN',{hour:'2-digit',minute:'2-digit',day:'2-digit',month:'2-digit',year:'numeric'}).format(d);}
function chart(sel,items){const host=q(sel);if(!host)return;const total=(items||[]).reduce((s,i)=>s+Number(i.value||0),0);if(!total){host.innerHTML=empty();return;}if(typeof renderChart==='function'){renderChart(sel,items);return;}host.innerHTML='<div class="chart-list">'+items.map(i=>'<div class="chart-line"><span>'+esc(i.label)+'</span><div class="chart-track"><div class="chart-bar" style="width:'+Math.max(4,Math.round(Number(i.value||0)*100/total))+'%"></div></div><strong>'+fmt(i.value)+'</strong></div>').join('')+'</div>';}
function extra(sel,data){if(data.top&&data.top.length)return top(sel,data.top);if(data.layers)return layers(sel,data.layers);if(data.reports)return list(sel,data.reports);return list(sel,[]);}
function top(sel,rows){const host=q(sel);if(!host)return;const livestock=rows&&rows[0]&&Object.prototype.hasOwnProperty.call(rows[0],'livestock_total');const head=livestock?'<th>M\u00e3 h\u1ed9</th><th>Ch\u1ee7 h\u1ed9</th><th>Lo\u1ea1i</th><th>V\u1eadt nu\u00f4i</th>':'<th>M\u00e3 h\u1ed9</th><th>Ch\u1ee7 h\u1ed9</th><th>Ho\u1ea1t \u0111\u1ed9ng</th><th>Lao \u0111\u1ed9ng</th>';host.innerHTML='<div class="table-responsive"><table class="table table-sm align-middle mb-0"><thead><tr>'+head+'</tr></thead><tbody>'+rows.map(r=>'<tr><td>'+esc(r.household_code)+'</td><td>'+esc(r.head_citizen_name)+'</td><td>'+fmt(livestock?r.livestock_types:r.activity_count)+'</td><td>'+fmt(livestock?r.livestock_total:r.worker_count)+'</td></tr>').join('')+'</tbody></table></div>';}
function layers(sel,items){const host=q(sel);if(!host)return;host.innerHTML='<div class="d-grid gap-2">'+(items||[]).map((x,i)=>'<label class="form-check d-flex align-items-center gap-2"><input class="form-check-input" type="checkbox" checked data-dashboard-layer="'+i+'"><span>'+esc(x)+'</span></label>').join('')+'</div>';}
function list(sel,items){const host=q(sel);if(!host)return;if(!items||!items.length){host.innerHTML=empty();return;}host.innerHTML='<div class="dashboard-metric-stack">'+items.map(x=>'<div class="dashboard-metric-line"><span>'+esc(typeof x==='string'?x:x.label)+'</span><strong>'+(typeof x==='string'?'':esc(fmt(x.value||0)))+'</strong></div>').join('')+'</div>';}
function renderError(cfg,e){const host=q(cfg.kpis);if(host)host.innerHTML='<div class="alert alert-danger mb-0">'+esc(e.message||'Không tải được Dashboard')+'</div>';}
function currentScreen(){return window.Thon09Platform?.navigation?.current?.()?.screenId||window.App?.screen||document.querySelector('.screen.active')?.id?.replace(/Screen$/,'')||'dashboard';}
function screenFromTarget(target){return target?.closest?.('.screen')?.id?.replace(/Screen$/,'')||currentScreen();}
function registerDashboardActions(){const actions=window.Thon09Platform&&window.Thon09Platform.actions;if(!actions||typeof actions.register!=='function')return;actions.register('moduleDashboard.refresh',ctx=>load(screenFromTarget(ctx.target),true));actions.register('moduleDashboard.clear',ctx=>{const host=ctx.target?.closest?.('.screen');qa('[data-dashboard-filter]',host||document).forEach(el=>el.value='');return load(screenFromTarget(ctx.target),true);});}
function bind(screen){const host=q('#'+screen+'Screen');if(!host||host.dataset.dashboardBound==='1')return;host.dataset.dashboardBound='1';qa('[data-dashboard-filter]',host).forEach(el=>el.addEventListener('change',()=>load(screen,true)));}
function activate(screen){if(configs[screen])load(screen,false);}
document.addEventListener('thon09:screen-change',e=>activate(e.detail?.screen));
document.addEventListener('DOMContentLoaded',()=>{registerDashboardActions();const active=q('.screen.active');if(active)activate(active.id.replace(/Screen$/,''));});
window.loadModuleDashboard=(screen,force)=>load(screen||currentScreen(),!!force);
})();
